import{_ as a,o as t,c as i,ae as s}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Apple Ads Overview","description":"","frontmatter":{"title":"Apple Ads Overview","slug":"apple-ads"},"headers":[],"relativePath":"marketer-hub/apple-ads.md","filePath":"marketer-hub/apple-ads.md"}'),o={name:"marketer-hub/apple-ads.md"};function r(n,e,l,p,d,h){return t(),i("div",null,[...e[0]||(e[0]=[s('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch can help track your <strong>Apple Ads</strong> campaigns by fetching the Apple Ads Attribution API. You can then use the parameters you&#39;ve set in the Apple Ads dashboard, parameters such as the campaign name, and take special action in your app after an install, or simply track the effectiveness of a campaign in the Branch dashboard, along with your other Branch statistics, such as total installs, referrals, and app link statistics.</p><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><ol><li><p>Branch integrates with Apple Ads through the <a href="https://searchads.apple.com/help/reporting/0028-apple-ads-attribution-api" target="_blank" rel="noreferrer">Apple Ads Attribution API</a>.</p></li><li><p>Once campaigns are launched, User see an ad to download the app.</p></li><li><p>User installs the app and performs in-app events (ex. PURCHASE)</p><ol><li>The Branch SDK captures the Apple Ads token for attribution or is set through a server-to-server implementation</li></ol></li><li><p>Branch communicates with Apple Ads through the Attribution API and sends Apple data about the conversion.</p></li><li><p>Apple Ads claims conversions by sending the cost/click/impression data that sourced it to Branch.</p></li><li><p>The Branch Dashboard will update reports for you to be able to compare and measure ad campaigns across campaigns, keywords, etc.</p></li></ol><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><h4 id="cost-data-and-other-dimensions" tabindex="-1">Cost data and other dimensions <a class="header-anchor" href="#cost-data-and-other-dimensions" aria-label="Permalink to &quot;Cost data and other dimensions&quot;">​</a></h4><p>When selecting cost with <code>ad id/name</code> or <code>creative id/name</code>, but not including <code>keyword/keyword id</code>, cost will show up for both types of product pages. You may see specific columns/dimensions displayed as <strong>Unpopulated</strong> in your Dashboard reports. This is due to limitations from the Apple Ads and what dimensions they can send for the Cost Data.</p><div class="info custom-block"><p class="custom-block-title">Cost Data Support</p><ul><li>To view the cost metrics Branch provides, please see <a href="./what-is-a-self-attributing-network.html#san-cost-data">SAN Cost Data</a>.</li><li>If you&#39;re seeing discrepancies, please see <a href="./common-sources-of-san-reporting-discrepancies.html">Common Sources of SAN Reporting Discrepancies</a>.</li></ul></div><h4 id="deep-linking" tabindex="-1">Deep linking <a class="header-anchor" href="#deep-linking" aria-label="Permalink to &quot;Deep linking&quot;">​</a></h4><p>Since this integration doesn&#39;t utilize Branch Links, options for deep linking are limited. We&#39;ll pass back the value you use for <code>campaign</code> in the Apple Ads dashboard. Since this value is controlled by you, you can put anything there, but it will reflect on the Branch dashboard. We will track installs regularly.</p><p>You can retrieve this parameter in the app to be used for <a href="./ios-advanced-features.html#general-deep-linking">deep linking</a>.</p><h2 id="faqs" tabindex="-1">FAQs <a class="header-anchor" href="#faqs" aria-label="Permalink to &quot;FAQs&quot;">​</a></h2><details><summary>Why does CAMPAIGN or CAMPAIGN ID for Apple Ads in Branch Show CampaignName and 1234567890?</summary><p><a href="https://developer.apple.com/documentation/iad/setting_up_apple_search_ads_attribution" target="_blank" rel="noreferrer">Apple Ads</a> will pass dummy values of &quot;CampaignName&quot; and &quot;1234567890&quot; if distributing the builds in debug mode or a test version using TestFlight. To fix this, disable debug mode and/or release live version.</p></details>',13)])])}const m=a(o,[["render",r]]);export{u as __pageData,m as default};
